+    fn with_no_grad_restores_state_after_panic() {
+        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
+        let unwind = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
+            session.with_no_grad(|s| {
